/// All errors that can occur when using `liter-llm`.
public enum LiterLlmError: Swift.Error {
    /// `status` preserves the exact HTTP status code received (401 or 403).
    case authentication(message: String, status: UInt16)
    case rateLimited(message: String, retryAfter: Duration?)
    /// `status` preserves the exact HTTP status code received (400, 405, 413, 422, …).
    case badRequest(message: String, status: UInt16)
    case contextWindowExceeded(message: String)
    case contentPolicy(message: String)
    case notFound(message: String)
    /// `status` preserves the exact HTTP status code received (500, or other 5xx not covered
    /// by `ServiceUnavailable`).
    case serverError(message: String, status: UInt16)
    /// `status` preserves the exact HTTP status code received (502, 503, or 504).
    case serviceUnavailable(message: String, status: UInt16)
    case timeout
    /// A catch-all for errors that occur during streaming response processing.
    ///
    /// This variant covers multiple sub-conditions including UTF-8 decoding
    /// failures, CRC/checksum mismatches (AWS EventStream), JSON parse errors
    /// in individual SSE chunks, and buffer overflow conditions.  The `message`
    /// field contains a human-readable description of the specific failure.
    case streaming(message: String)
    case endpointNotSupported(message: String, endpoint: String, provider: String)
    case invalidHeader(message: String, name: String, reason: String)
    case serialization(message: String, field0: String)
    case budgetExceeded(message: String, model: String?)
    case hookRejected(message: String)
    /// An internal logic error (e.g. unexpected Tower response variant).
    ///
    /// This should never surface in normal operation — if it does, it
    /// indicates a bug in the library.
    case internalError(message: String)
}

extension LiterLlmError {
    public var statusCode: UInt16 {
        switch self {
        case .authentication(message: _, status: let matched): return matched
        case .rateLimited(message: _, retryAfter: _): return 0
        case .badRequest(message: _, status: let matched): return matched
        case .contextWindowExceeded(message: _): return 0
        case .contentPolicy(message: _): return 0
        case .notFound(message: _): return 0
        case .serverError(message: _, status: let matched): return matched
        case .serviceUnavailable(message: _, status: let matched): return matched
        case .timeout: return 0
        case .streaming(message: _): return 0
        case .endpointNotSupported(endpoint: _, provider: _): return 0
        case .invalidHeader(name: _, reason: _): return 0
        case .serialization(field0: _): return 0
        case .budgetExceeded(message: _, model: _): return 0
        case .hookRejected(message: _): return 0
        case .internalError(message: _): return 0
        }
    }
    public var isTransient: Bool {
        switch self {
        case .authentication(message: _, status: _): return false
        case .rateLimited(message: _, retryAfter: _): return false
        case .badRequest(message: _, status: _): return false
        case .contextWindowExceeded(message: _): return false
        case .contentPolicy(message: _): return false
        case .notFound(message: _): return false
        case .serverError(message: _, status: _): return false
        case .serviceUnavailable(message: _, status: _): return false
        case .timeout: return false
        case .streaming(message: _): return false
        case .endpointNotSupported(endpoint: _, provider: _): return false
        case .invalidHeader(name: _, reason: _): return false
        case .serialization(field0: _): return false
        case .budgetExceeded(message: _, model: _): return false
        case .hookRejected(message: _): return false
        case .internalError(message: _): return false
        }
    }
    public var errorType: String {
        switch self {
        case .authentication(message: _, status: _): return ""
        case .rateLimited(message: _, retryAfter: _): return ""
        case .badRequest(message: _, status: _): return ""
        case .contextWindowExceeded(message: _): return ""
        case .contentPolicy(message: _): return ""
        case .notFound(message: _): return ""
        case .serverError(message: _, status: _): return ""
        case .serviceUnavailable(message: _, status: _): return ""
        case .timeout: return ""
        case .streaming(message: _): return ""
        case .endpointNotSupported(endpoint: _, provider: _): return ""
        case .invalidHeader(name: _, reason: _): return ""
        case .serialization(field0: _): return ""
        case .budgetExceeded(message: _, model: _): return ""
        case .hookRejected(message: _): return ""
        case .internalError(message: _): return ""
        }
    }
}

public final class DefaultClient {
    private let inner: RustBridge.DefaultClient
    public init(apiKey: String, baseUrl: String? = nil) throws {
        self.inner = try RustBridge.createDefaultClient(apiKey, baseUrl)
    }
    public func chat(_ req: ChatCompletionRequest) async throws -> ChatCompletionResponse {
        return try ChatCompletionResponse(try await RustBridge.defaultClientChat(self.inner, req))
    }
    public func embed(_ req: EmbeddingRequest) async throws -> EmbeddingResponse {
        return try EmbeddingResponse(try await RustBridge.defaultClientEmbed(self.inner, req))
    }
    public func listModels() async throws -> ModelsListResponse {
        return try ModelsListResponse(try await RustBridge.defaultClientListModels(self.inner))
    }
    public func imageGenerate(_ req: CreateImageRequest) async throws -> ImagesResponse {
        return try ImagesResponse(try await RustBridge.defaultClientImageGenerate(self.inner, try req.intoRust()))
    }
    public func speech(_ req: CreateSpeechRequest) async throws -> Data {
        let _bytes = try await RustBridge.defaultClientSpeech(self.inner, try req.intoRust())
        return Data(_bytes.map { $0 })
    }
    public func transcribe(_ req: CreateTranscriptionRequest) async throws -> TranscriptionResponse {
        return try TranscriptionResponse(try await RustBridge.defaultClientTranscribe(self.inner, try req.intoRust()))
    }
    public func moderate(_ req: ModerationRequest) async throws -> ModerationResponse {
        return try ModerationResponse(try await RustBridge.defaultClientModerate(self.inner, req))
    }
    public func rerank(_ req: RerankRequest) async throws -> RerankResponse {
        return try await RustBridge.defaultClientRerank(self.inner, req)
    }
    public func search(_ req: SearchRequest) async throws -> SearchResponse {
        return try SearchResponse(try await RustBridge.defaultClientSearch(self.inner, try req.intoRust()))
    }
    public func ocr(_ req: OcrRequest) async throws -> OcrResponse {
        return try OcrResponse(try await RustBridge.defaultClientOcr(self.inner, req))
    }
    public func createFile(_ req: CreateFileRequest) async throws -> FileObject {
        return try FileObject(try await RustBridge.defaultClientCreateFile(self.inner, try req.intoRust()))
    }
    public func retrieveFile(_ fileId: String) async throws -> FileObject {
        return try FileObject(try await RustBridge.defaultClientRetrieveFile(self.inner, fileId))
    }
    public func deleteFile(_ fileId: String) async throws -> DeleteResponse {
        return try DeleteResponse(try await RustBridge.defaultClientDeleteFile(self.inner, fileId))
    }
    public func listFiles(_ query: FileListQuery?) async throws -> FileListResponse {
        return try FileListResponse(try await RustBridge.defaultClientListFiles(self.inner, try query?.intoRust()))
    }
    public func fileContent(_ fileId: String) async throws -> Data {
        let _bytes = try await RustBridge.defaultClientFileContent(self.inner, fileId)
        return Data(_bytes.map { $0 })
    }
    public func createBatch(_ req: CreateBatchRequest) async throws -> BatchObject {
        return try await RustBridge.defaultClientCreateBatch(self.inner, req)
    }
    public func retrieveBatch(_ batchId: String) async throws -> BatchObject {
        return try await RustBridge.defaultClientRetrieveBatch(self.inner, batchId)
    }
    public func listBatches(_ query: BatchListQuery?) async throws -> BatchListResponse {
        return try await RustBridge.defaultClientListBatches(self.inner, try query?.intoRust())
    }
    public func cancelBatch(_ batchId: String) async throws -> BatchObject {
        return try await RustBridge.defaultClientCancelBatch(self.inner, batchId)
    }
    public func createResponse(_ req: CreateResponseRequest) async throws -> ResponseObject {
        return try await RustBridge.defaultClientCreateResponse(self.inner, req)
    }
    public func retrieveResponse(_ responseId: String) async throws -> ResponseObject {
        return try await RustBridge.defaultClientRetrieveResponse(self.inner, responseId)
    }
    public func cancelResponse(_ responseId: String) async throws -> ResponseObject {
        return try await RustBridge.defaultClientCancelResponse(self.inner, responseId)
    }
    public func chatStream(_ req: ChatCompletionRequest) async throws -> AsyncThrowingStream<ChatCompletionChunk, Error> {
        let inner = self.inner
        let handle = try await Task.detached(priority: .userInitiated) {
            try RustBridge.defaultClientChatStreamStart(inner, req)
        }.value

        return AsyncThrowingStream<ChatCompletionChunk, Error> { continuation in
            let task = Task.detached(priority: .userInitiated) {
                do {
                    while !Task.isCancelled {
                        let json = try handle.next().toString()
                        if json.isEmpty { break }
                        let chunkData = json.data(using: .utf8) ?? Data()
                        let chunk = try JSONDecoder().decode(ChatCompletionChunk.self, from: chunkData)
                        continuation.yield(chunk)
                    }
                    continuation.finish()
                } catch {
                    continuation.finish(throwing: error)
                }
            }
            continuation.onTermination = { _ in task.cancel() }
        }
    }
}

// MARK: - Sendable conformance for DefaultClient (streaming client inner)
// swift-bridge opaque types are not automatically Sendable.
// Captured by Task.detached in streaming methods — Rust type is Send + Sync.
extension RustBridge.DefaultClient: @unchecked Sendable {}
// MARK: - Sendable conformance for DefaultClientChatStreamStreamHandle
// swift-bridge opaque types are not automatically Sendable.  The Rust
// side uses Mutex<stream> + tokio Runtime — both Send + Sync — so
// @unchecked is correct: thread-safety is enforced by Rust.
extension RustBridge.DefaultClientChatStreamStreamHandle: @unchecked Sendable {}
// MARK: - Sendable conformance for ChatCompletionRequest (streaming request param)
// swift-bridge opaque types are not automatically Sendable.
// Passed into Task.detached for streaming — Rust type is Send + Sync.
extension RustBridge.ChatCompletionRequest: @unchecked Sendable {}
